import java.util.Scanner;

public class BufferOverflowExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Creating a fixed-size array to store user input
        char[] buffer = new char[10];

        // Copying user input into the buffer array with proper bounds checking
        int length = Math.min(name.length(), buffer.length);
        name.getChars(0, length, buffer, 0);

        System.out.println("Your name is: " + new String(buffer));
    }
}

### Explanation:
